  data.mystery = 0;
  for (int i = 0; i < 5; i++) {
    data.mystery = data.mystery + data.numbers[i];
  }
}
int main() {
  stat_double d;
  d.numbers[0] = 1.0;
  d.numbers[1] = 2.0;
  d.numbers[2] = 3.0;
  d.numbers[3] = 4.0;
  d.numbers[4] = 5.0;
  who_am_i(d);
  cout << d.mystery << endl;
  return 0;
}

